import json
import re
import pandas as pd

# Load data
with open(locals()['var_functions.query_db:42'], 'r') as f:
    publications = json.load(f)

# Process CPC codes
cpc_counts = {}
pattern = re.compile(r'^([A-Z][0-9]{2}[A-Z])([0-9]{1,3})')

for pub in publications:
    try:
        year = int(pub['publication_date'].split(', ')[1])
        codes = json.loads(pub['cpc'])
        for c in codes:
            code = c['code']
            if '/' in code:
                match = pattern.match(code.split('/')[0])
                if match:
                    level5 = match.group(1) + match.group(2)
                    if year not in cpc_counts:
                        cpc_counts[year] = {}
                    cpc_counts[year][level5] = cpc_counts[year].get(level5, 0) + 1
    except:
        continue

# Calculate EMA and find 2022 best codes
codes_by_year = []
for year in sorted(cpc_counts.keys()):
    for code in cpc_counts[year]:
        codes_by_year.append((year, code, cpc_counts[year][code]))

df = pd.DataFrame(codes_by_year, columns=['year', 'code', 'count'])
pivot = df.pivot(index='year', columns='code', values='count').fillna(0)
ema = pivot.ewm(alpha=0.2, adjust=False).mean()

best_2022 = []
for code in ema.columns:
    if code in ema.columns and ema[code].idxmax() == 2022:
        best_2022.append(code)

# Create final result string
result = ', '.join(sorted(best_2022))
print('CALCULATED:', len(best_2022), 'codes')
print('__RESULT__:')
print(result)

